var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"오, 로저. 왜 아무런 말이 없나요?","JPN":"ああ、ロジャー。どうして何も言わないんですか？","ENG":"Uh, Roger? Why aren't you saying anything?","TWN":"呃。為什麼你一句話也不說？"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"아, 아닙니다. 조금 현실감 없는 이야기라 그만.","JPN":"い、いいえ。少し現実感覚のない話だったので、つい。","ENG":"O-oh, my apologies. It's all just a little too hard to believe.","TWN":"啊，不，不是的。只是感覺故事有點不太真實而已。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"그럼… 마드모아젤이 투옥된 건 그것 때문인가요?","JPN":"では……マドモアゼルが投獄されたのは、それのせいなのですか？","ENG":"Then... are you imprisoned because of that, mademoiselle?","TWN":"那麼……你被囚禁是因為這個嗎？"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아뇨? 그 녀석들은 터커랑 샤크스 해적단이지 시그마 해적단이 아니잖아요.","JPN":"いいえ？　あいつらはターカーとシャークス海賊団で、シグマ海賊団ではないですよ。","ENG":"No. They were Tucker and the Sharks, not the Sigma Pirates.","TWN":"不是啊？那些傢伙是塔克和大白鯊海盜團的……"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아직 절반도 안 왔어요. 얘기가 길어질 거라 했잖아요?","JPN":"まだ半分も話してません。長くなるって言いましたよね？","ENG":"We're not even halfway there yet. I told you it was going to be a long story.","TWN":"還沒講到西格瑪海盜團呢。我不是說過會講很久嗎？"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"어디 보자-.","JPN":"どれどれー","ENG":"Let's see...","TWN":"讓我想想……"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"프론트베이에서의 일은 뼈아팠지만, 재판에서는 어찌어찌 합의를 보는 데 성공했어요.","JPN":"フロントベイでのことは痛い経験でしたが、裁判ではなんとか合意することに成功したんです。","ENG":"The Front Bay incident did sting, but I managed to reach a settlement at trial.","TWN":"在前灣的事情雖然很慘痛，但幸好在判決中達成和解。"},"stage":{"bg":"FRONTBAY_WALL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"그걸 합의하다니. 고용하신 변호사 분을 개인적으로 뵙고 싶군요.","JPN":"それを合意できたとは。担当した弁護士さんに、個人的に一度お会いしてみたいですね。","ENG":"A settlement? I wish to meet this lawyer of yours.","TWN":"竟然可以和解？真想親眼見見你找的那個律師。"},"stage":{"bg":"FRONTBAY_WALL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"운이 좋았어요. 해적이 얽힌 문제라 프론트베이 측도 강하게 나올 수는 없었거든요.","JPN":"運が良かったんです。海賊絡みの問題だったので、フロントベイ側も強くはでれなかったから。","ENG":"I got lucky. With the pirates involved, Front Bay couldn't really come out strong.","TWN":"應該說運氣不錯。因為涉及到海盜問題，前灣那邊也強硬不起來。"},"stage":{"bg":"FRONTBAY_WALL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"그 뒤로는 뭐… 빚은 갚아야 하니 아는 사람한테 도움을 요청했죠.","JPN":"その後は、まあ……借金は返さないといけなかったので、知り合いに助けを求めたんです。","ENG":"And after that... I had to repay my debt, so I called in a friend for a favor.","TWN":"之後嘛……因為要還債，只好向認識的人求助了。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"운 좋게도 금융권에서 일하는 지인이 있었거든요. 돈이라도 생기면 일단 어떻게든 되지 않을까 싶었고.","JPN":"運よく金融機関で働いてる知り合いがいたんですよね。お金が手に入ったら、なんとかなるんじゃないかなーとも思ったし。","ENG":"Coincidentally, she worked in finance. And I thought if I had the money, I could sort things out.","TWN":"碰巧的是，我有個在金融界工作的朋友。我想著有了錢，事情總會有辦法解決的。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"그러지 말았어야 했는데…!","JPN":"それじゃダメだったのに……！","ENG":"But I shouldn't have done that...!","TWN":"我、我就不該那樣做的……！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"…음.","JPN":"……うーん。","ENG":"...Mm.","TWN":"……嗯。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그래서, 유피 언니는 돈을 빌리고 싶다는 거야?","JPN":"で、ユピさんはお金を借りたいってこと？","ENG":"So, you want to borrow some money, Yuppie?","TWN":"所以，悠菲姊姊是想借錢嗎？"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"넵. 지인 찬스로 어떻게든 안 될까요…….","JPN":"はい。知り合いってことでなんとかできないでしょうか……","ENG":"Yes. Could you do me a solid?","TWN":"是的。能不能透過熟人關係想想辦法……"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"확실히 여기가 돈을 빌려주는 장소는 맞지만… 오랜만에 만났는데 조금 당황스럽달까.","JPN":"確かにここはお金を貸してあげるところではあるんだけど……久しぶりに会ったのにちょっと困惑してるっていうか。","ENG":"You came to the right establishment to get a loan, but... it's been a while since we last met, and I'm a little taken aback.","TWN":"這裡確實是借錢的地方……不過好久不見了，有點讓我措手不及呢……"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"대체 뭘 했길래 빚쟁이가 된 거야?","JPN":"なんで借金がそんなに多くなったんだよ？","ENG":"What did you do to be in so much debt?","TWN":"姊姊到底做了什麼，怎麼會欠錢呢？"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"항구 도시인 프론트베이에서 함선 테러를 일으켰군요, 휴먼.","JPN":"港町であるフロントベイで艦船テロを起こしましたか、ヒューマン。","ENG":"You were involved with the Front Bay ship terrorism, human.","TWN":"你在港口城市前灣對艦船發動恐怖攻擊是嗎，人類。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"빚의 규모를 보면 프론트베이보다 본인 인생을 테러한 것 같긴 합니다만.","JPN":"借金の規模からすると、フロントベイより自分の人生をテロしたようですが。","ENG":"But looking at the size of your debt, it seems that more damage was done to your own life than to Front Bay.","TWN":"不過看你的債務規模，比較像是對自己的人生發動恐怖攻擊。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"흐아아앙…!!","JPN":"ふえええん……！！","ENG":"WAAAAAH...!!","TWN":"嗚啊啊啊……！！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"뚜, 뚝 그쳐, 언니! 애도 아니면서 그렇게 울면 어떡해?","JPN":"ちょ、ちょっと泣かないでよ、ユピさん！　子どもじゃないんだし、泣いてどうなるわけでもないでしょ？","ENG":"Y-Yuppie, stop crying! You're not a little kid anymore!","TWN":"停，停下，姊姊！你又不是小孩子，怎麼能這樣哭呢？"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"니가 내 입장이 돼 보세요오…! 억울하게 빚쟁이가 됐는데 안 울게 생겼냐고요오-!","JPN":"私の立場になってみなさいよぉ……！　無念にも巨額の負債者になっちゃって、そりゃ泣くでしょうー！","ENG":"Try putting yourself in my shoes...! Wouldn't you also be crying if you were in debt for something you didn't do?!","TWN":"你試試站在我的立場想想……！莫名其妙欠一屁股債，能不哭嗎！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"음… 그렇다는데 어떻게 안 될까, 호라이즌?","JPN":"うーん……そういうことらしいから、なんとかできないかな？　ホライズン。","ENG":"Mm... Is there anything we can do, Horizon?","TWN":"嗯……就是這樣了，可以嗎，地平線？"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};